class DFA:
    def __init__(self, states, alphabet, transition, start, accept):
        self.states = states
        self.alphabet = alphabet
        self.transition = transition
        self.start = start
        self.accept = accept

def accepts(self, input_string):
        state = self.start
        for symbol in input_string:
            if symbol not in self.alphabet:
                return False
            state = self.transition.get((state, symbol))
        return state in self.accept

# States: remainder when number is divided by 3
# 0 = divisible by 3, 1 = remainder 1, 2 = remainder 2
states = {0, 1, 2}
alphabet = {'0', '1'}
transition = {
    (0, '0'): 0, (0, '1'): 1,
    (1, '0'): 2, (1, '1'): 0,
    (2, '0'): 1, (2, '1'): 2
}
start = 0
accept = {0}

dfa = DFA(states, alphabet, transition, start, accept)
print(dfa.accepts('110'))  # True (6 is divisible by 3)
print(dfa.accepts('101'))  # False (5 is not divisible by 3)

import re

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def current_token(self):
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return None

    def consume(self):
        token = self.current_token()
        self.pos += 1
        return token

    # Grammar: E → T { ('+' | '-') T }
    #         T → F { ('*' | '/') F }
    #         F → number | '(' E ')'

    def parse_expression(self):
        result = self.parse_term()
        while self.current_token() in ['+', '-']:
            op = self.consume()
            right = self.parse_term()
            result = ('binop', op, result, right)
        return result

    def parse_term(self):
        result = self.parse_factor()
        while self.current_token() in ['*', '/']:
            op = self.consume()
            right = self.parse_factor()
            result = ('binop', op, result, right)
        return result

    def parse_factor(self):
        token = self.current_token()
        if token == '(':
            self.consume()  # '('
            result = self.parse_expression()
            self.consume()  # ')'
            return result
        elif token.isdigit():
            self.consume()
            return ('num', int(token))
        else:
            raise ValueError(f"Unexpected token: {token}")

# Example usage
tokens = ['3', '+', '5', '*', '2']
parser = Parser(tokens)
ast = parser.parse_expression()
print(ast)  # ('binop', '+', ('num', 3), ('binop', '*', ('num', 5), ('num', 2)))

