/* 
 * Context-Free Grammar for Simple Language:
 * 
 * Non-terminals: PROGRAM, STMT, EXPR, TERM, FACTOR
 * Terminals: id, num, +, -, *, /, (, ), ;
 * 
 * Grammar Rules (in BNF-like form):
 * PROGRAM   → STMT { ';' STMT }
 * STMT      → id '=' EXPR | EXPR
 * EXPR      → TERM { ('+' | '-') TERM }
 * TERM      → FACTOR { ('*' | '/') FACTOR }
 * FACTOR    → id | num | '(' EXPR ')'
 */

// Sample derivations:
// PROGRAM → x = 3 + 5 * 2
// STMT    → id = EXPR
// EXPR    → TERM → FACTOR * FACTOR → num * FACTOR
//
// This grammar enforces operator precedence:
// () highest, then *,/ then +,-

typedef enum {ID, NUM, PLUS, MINUS, MUL, DIV, LPAREN, RPAREN, SEMI, EQ, END} TokenType;

typedef struct ASTNode {
